func (fx *PipelineServiceTrainingPipelineTestSuiteConfig) testGet(t *testing.T) {
	fx.maybeSkip(t)
	// Method should fail with InvalidArgument if no name is provided.
	t.Run("missing name", func(t *testing.T) {
		fx.maybeSkip(t)
		req := &GetTrainingPipelineRequest{}
		req.SetName("")
		_, err := fx.Service().GetTrainingPipeline(fx.Context(), req)
		assert.Equal(t, codes.InvalidArgument, status.Code(err), err)
	})

	// Method should fail with InvalidArgument if the provided name is not valid.
	t.Run("invalid name", func(t *testing.T) {
		fx.maybeSkip(t)
		req := &GetTrainingPipelineRequest{}
		req.SetName("invalid resource name")
		_, err := fx.Service().GetTrainingPipeline(fx.Context(), req)
		assert.Equal(t, codes.InvalidArgument, status.Code(err), err)
	})

	// Resource should be returned without errors if it exists.
	t.Run("exists", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		created := fx.create(t, parent)
		req := &GetTrainingPipelineRequest{}
		req.SetName(created.GetName())
		msg, err := fx.Service().GetTrainingPipeline(fx.Context(), req)
		assert.NilError(t, err)
		assert.DeepEqual(t, msg, created, protocmp.Transform())
	})

	// Method should fail with NotFound if the resource does not exist.
	t.Run("not found", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		created := fx.create(t, parent)
		req := &GetTrainingPipelineRequest{}
		req.SetName(created.GetName() + "notfound")
		_, err := fx.Service().GetTrainingPipeline(fx.Context(), req)
		assert.Equal(t, codes.NotFound, status.Code(err), err)
	})

	// Method should fail with InvalidArgument if the provided name only contains wildcards ('-')
	t.Run("only wildcards", func(t *testing.T) {
		fx.maybeSkip(t)
		req := &GetTrainingPipelineRequest{}
		req.SetName("projects/-/locations/-/trainingPipelines/-")
		_, err := fx.Service().GetTrainingPipeline(fx.Context(), req)
		assert.Equal(t, codes.InvalidArgument, status.Code(err), err)
	})

}

func (fx *PipelineServiceTrainingPipelineTestSuiteConfig) testList(t *testing.T) {
	fx.maybeSkip(t)
	// Method should fail with InvalidArgument if provided parent is invalid.
	t.Run("invalid parent", func(t *testing.T) {
		fx.maybeSkip(t)
		req := &ListTrainingPipelinesRequest{}
		req.SetParent("invalid resource name")
		_, err := fx.Service().ListTrainingPipelines(fx.Context(), req)
		assert.Equal(t, codes.InvalidArgument, status.Code(err), err)
	})

	// Method should fail with InvalidArgument is provided page token is not valid.
	t.Run("invalid page token", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		req := &ListTrainingPipelinesRequest{}
		req.SetParent(parent)
		req.SetPageToken("invalid page token")
		_, err := fx.Service().ListTrainingPipelines(fx.Context(), req)
		assert.Equal(t, codes.InvalidArgument, status.Code(err), err)
	})

	// Method should fail with InvalidArgument is provided page size is negative.
	t.Run("negative page size", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		req := &ListTrainingPipelinesRequest{}
		req.SetParent(parent)
		req.SetPageSize(-10)
		_, err := fx.Service().ListTrainingPipelines(fx.Context(), req)
		assert.Equal(t, codes.InvalidArgument, status.Code(err), err)
	})

	{
		const resourcesCount = 15
		parent := fx.nextParent(t, true)
		parentMsgs := make([]*TrainingPipeline, resourcesCount)
		for i := 0; i < resourcesCount; i++ {
			parentMsgs[i] = fx.create(t, parent)
		}

		// If parent is provided the method must only return resources
		// under that parent.
		t.Run("isolation", func(t *testing.T) {
			fx.maybeSkip(t)
			req := &ListTrainingPipelinesRequest{}
			req.SetParent(parent)
			req.SetPageSize(999)
			response, err := fx.Service().ListTrainingPipelines(fx.Context(), req)
			assert.NilError(t, err)
			assert.DeepEqual(
				t,
				parentMsgs,
				response.GetTrainingPipelines(),
				cmpopts.SortSlices(func(a, b *TrainingPipeline) bool {
					return a.GetName() < b.GetName()
				}),
				protocmp.Transform(),
			)
		})

		// If there are no more resources, next_page_token should not be set.
		t.Run("last page", func(t *testing.T) {
			fx.maybeSkip(t)
			req := &ListTrainingPipelinesRequest{}
			req.SetParent(parent)
			req.SetPageSize(resourcesCount)
			response, err := fx.Service().ListTrainingPipelines(fx.Context(), req)
			assert.NilError(t, err)
			assert.Equal(t, "", response.GetNextPageToken())
		})

		// If there are more resources, next_page_token should be set.
		t.Run("more pages", func(t *testing.T) {
			fx.maybeSkip(t)
			req := &ListTrainingPipelinesRequest{}
			req.SetParent(parent)
			req.SetPageSize(resourcesCount - 1)
			response, err := fx.Service().ListTrainingPipelines(fx.Context(), req)
			assert.NilError(t, err)
			assert.Check(t, response.GetNextPageToken() != "")
		})

		// Listing resource one by one should eventually return all resources.
		t.Run("one by one", func(t *testing.T) {
			fx.maybeSkip(t)
			msgs := make([]*TrainingPipeline, 0, resourcesCount)
			var nextPageToken string
			for {
				req := &ListTrainingPipelinesRequest{}
				req.SetParent(parent)
				req.SetPageSize(1)
				req.SetPageToken(nextPageToken)
				response, err := fx.Service().ListTrainingPipelines(fx.Context(), req)
				assert.NilError(t, err)
				assert.Equal(t, 1, len(response.GetTrainingPipelines()))
				msgs = append(msgs, response.GetTrainingPipelines()...)
				nextPageToken = response.GetNextPageToken()
				if nextPageToken == "" {
					break
				}
			}
			assert.DeepEqual(
				t,
				parentMsgs,
				msgs,
				cmpopts.SortSlices(func(a, b *TrainingPipeline) bool {
					return a.GetName() < b.GetName()
				}),
				protocmp.Transform(),
			)
		})

		// Method should not return deleted resources.
		t.Run("deleted", func(t *testing.T) {
			fx.maybeSkip(t)
			const deleteCount = 5
			for i := 0; i < deleteCount; i++ {
				delReq := &DeleteTrainingPipelineRequest{}
				delReq.SetName(parentMsgs[i].GetName())
				_, err := fx.Service().DeleteTrainingPipeline(fx.Context(), delReq)
				assert.NilError(t, err)
			}
			listReq := &ListTrainingPipelinesRequest{}
			listReq.SetParent(parent)
			listReq.SetPageSize(9999)
			response, err := fx.Service().ListTrainingPipelines(fx.Context(), listReq)
			assert.NilError(t, err)
			assert.DeepEqual(
				t,
				parentMsgs[deleteCount:],
				response.GetTrainingPipelines(),
				cmpopts.SortSlices(func(a, b *TrainingPipeline) bool {
					return a.GetName() < b.GetName()
				}),
				protocmp.Transform(),
			)
		})

	}
	{
		const resourcesCount = 101
		parent := fx.nextParent(t, true)
		parentMsgs := make([]*TrainingPipeline, resourcesCount)
		for i := 0; i < resourcesCount; i++ {
			parentMsgs[i] = fx.create(t, parent)
		}

		// Listing resource with page size zero should eventually return all resources.
		t.Run("page size zero", func(t *testing.T) {
			fx.maybeSkip(t)
			msgs := make([]*TrainingPipeline, 0, resourcesCount)
			var nextPageToken string
			for {
				req := &ListTrainingPipelinesRequest{}
				req.SetParent(parent)
				req.SetPageSize(0)
				req.SetPageToken(nextPageToken)
				page, err := fx.Service().ListTrainingPipelines(fx.Context(), req)
				assert.NilError(t, err)
				msgs = append(msgs, page.GetTrainingPipelines()...)
				nextPageToken = page.GetNextPageToken()
				if nextPageToken == "" {
					break
				}
			}
			assert.DeepEqual(
				t,
				parentMsgs,
				msgs,
				cmpopts.SortSlices(func(a, b *TrainingPipeline) bool {
					return a.GetName() < b.GetName()
				}),
				protocmp.Transform(),
			)
		})

	}
}

func (fx *PipelineServiceTrainingPipelineTestSuiteConfig) testDelete(t *testing.T) {
	fx.maybeSkip(t)
	// Method should fail with InvalidArgument if no name is provided.
	t.Run("missing name", func(t *testing.T) {
		fx.maybeSkip(t)
		req := &DeleteTrainingPipelineRequest{}
		req.SetName("")
		_, err := fx.Service().DeleteTrainingPipeline(fx.Context(), req)
		assert.Equal(t, codes.InvalidArgument, status.Code(err), err)
	})

	// Method should fail with InvalidArgument if the provided name is not valid.
	t.Run("invalid name", func(t *testing.T) {
		fx.maybeSkip(t)
		req := &DeleteTrainingPipelineRequest{}
		req.SetName("invalid resource name")
		_, err := fx.Service().DeleteTrainingPipeline(fx.Context(), req)
		assert.Equal(t, codes.InvalidArgument, status.Code(err), err)
	})

	// Resource should be deleted without errors if it exists.
	t.Run("exists", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		created := fx.create(t, parent)
		req := &DeleteTrainingPipelineRequest{}
		req.SetName(created.GetName())
		_, err := fx.Service().DeleteTrainingPipeline(fx.Context(), req)
		assert.NilError(t, err)
	})

	// Method should fail with NotFound if the resource does not exist.
	t.Run("not found", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		created := fx.create(t, parent)
		req := &DeleteTrainingPipelineRequest{}
		req.SetName(created.GetName() + "notfound")
		_, err := fx.Service().DeleteTrainingPipeline(fx.Context(), req)
		assert.Equal(t, codes.NotFound, status.Code(err), err)
	})

	// Method should fail with NotFound if the resource was already deleted. This also applies to soft-deletion.
	t.Run("already deleted", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		created := fx.create(t, parent)
		req1 := &DeleteTrainingPipelineRequest{}
		req1.SetName(created.GetName())
		deleted, err := fx.Service().DeleteTrainingPipeline(fx.Context(), req1)
		assert.NilError(t, err)
		_ = deleted
		req2 := &DeleteTrainingPipelineRequest{}
		req2.SetName(created.GetName())
		_, err = fx.Service().DeleteTrainingPipeline(fx.Context(), req2)
		assert.Equal(t, codes.NotFound, status.Code(err), err)
	})

	// Method should fail with InvalidArgument if the provided name only contains wildcards ('-')
	t.Run("only wildcards", func(t *testing.T) {
		fx.maybeSkip(t)
		req := &DeleteTrainingPipelineRequest{}
		req.SetName("projects/-/locations/-/trainingPipelines/-")
		_, err := fx.Service().DeleteTrainingPipeline(fx.Context(), req)
		assert.Equal(t, codes.InvalidArgument, status.Code(err), err)
	})

}

func (fx *PipelineServiceTrainingPipelineTestSuiteConfig) nextParent(t *testing.T, pristine bool) string {
	if pristine {
		fx.currParent++
	}
	if fx.currParent >= len(fx.Parents) {
		t.Fatal("need at least", fx.currParent+1, "parents")
	}
	return fx.Parents[fx.currParent]
}

func (fx *PipelineServiceTrainingPipelineTestSuiteConfig) peekNextParent(t *testing.T) string {
	next := fx.currParent + 1
	if next >= len(fx.Parents) {
		t.Fatal("need at least", next+1, "parents")
	}
	return fx.Parents[next]
}

func (fx *PipelineServiceTrainingPipelineTestSuiteConfig) maybeSkip(t *testing.T) {
	for _, skip := range fx.Skip {
		if strings.Contains(t.Name(), skip) {
			t.Skip("skipped because of .Skip")
		}
	}
}

func (fx *PipelineServiceTrainingPipelineTestSuiteConfig) create(t *testing.T, parent string) *TrainingPipeline {
	t.Helper()
	req := &CreateTrainingPipelineRequest{}
	req.SetParent(parent)
	req.SetTrainingPipeline(fx.Create(parent))
	created, err := fx.Service().CreateTrainingPipeline(fx.Context(), req)
	assert.NilError(t, err)
	return created
}
